using Microsoft.AspNetCore.Mvc;

public class ReportController : Controller
{
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();

        // Return a FileContentResult — the framework handles headers and
        // flushing the response. No Response.End() equivalent needed.
        return File(
            System.Text.Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv");
    }

    [HttpPost]
    public IActionResult Redirect()
    {
        if (!User.Identity!.IsAuthenticated)
        {
            // RedirectResult ends the action via a normal return — no
            // Thread.Abort, no endResponse parameter.
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // No ThreadAbortException catch needed — redirects don't throw.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport() => "col1,col2\nval1,val2";
    private void ProcessRequest() { }
    private void LogError(Exception ex) { }
}
